import javax.jws.WebMethod;
import javax.jws.WebService;
import javax.jws.soap.SOAPBinding;
import javax.xml.ws.Endpoint;
import javax.xml.ws.WebServiceException;
import java.util.List;

@WebService
@SOAPBinding(style = SOAPBinding.Style.DOCUMENT, use = SOAPBinding.Use.LITERAL)
public class OrderProcessingService {

    @WebMethod
    public String processOrder(List<OrderItem> orderItems) {
        if (orderItems == null || orderItems.isEmpty()) {
            throw new WebServiceException("Invalid order items");
        }

        double totalPrice = 0.0;
        for (OrderItem item : orderItems) {
            if (item.getPrice() < 0 || item.getQuantity() <= 0) {
                throw new WebServiceException("Invalid item price or quantity");
            }
            totalPrice += item.getPrice() * item.getQuantity();
        }

        // Process the order (e.g., save to database, update inventory)
        // For simplicity, we just return a confirmation message
        return "Order processed successfully. Total Price: $" + totalPrice;
    }

    public static void main(String[] args) {
        Endpoint.publish("http://localhost:8080/OrderProcessingService", new OrderProcessingService());
    }
}

class OrderItem {
    private String itemName;
    private double price;
    private int quantity;

    public OrderItem(String itemName, double price, int quantity) {
        this.itemName = itemName;
        this.price = price;
        this.quantity = quantity;
    }

    public String getItemName() {
        return itemName;
    }

    public double getPrice() {
        return price;
    }

    public int getQuantity() {
        return quantity;
    }
}